export function GlossarySection({ pageContent, data }: SectionProps) {
  const d = data || pageContent || {}
  const items = d.items || []
  if (!items.length) return null
  return (
    <section style={{ padding: s.section, background: c.bg }}>
      <div style={{ maxWidth: '800px', margin: '0 auto' }}>
