          <button style={{ padding:'0.75rem 1.5rem',background:c.accent,color:c.primary,borderRadius:r.full,border:'none',fontWeight:700,cursor:'pointer',fontSize:'0.9rem' }}>{d.buttonText || "Suscribirme"}</button>
