      <div style={{ maxWidth: sz.contentWide, margin: '0 auto', textAlign: 'center' }}>
        {d.title && <h2 style={{ fontSize:'clamp(1.4rem,2.5vw,2rem)',fontWeight:700, marginBottom:'2rem' }}>{d.title}</h2>}
