md = f"""# Component Registry — SECTION_MAP (26 Components)

**Status:** Current | **Last Validated:** [REDACTED_PHONE] | **Scope:** All registered section components

---

## How to Read This

Each component has:
- **section_ids** — The `id` value in `nexa-pages/*.json` that triggers this component
- **content_key** — The `content` value pattern in page configs (\\$PAGE = resolved parent key)
- **reads_from_pageContent** — Which key inside the `pageContent` object the component accesses
- **data_shape** — For extra-section components that use the `data` prop directly
- **expects** — The JSON keys/types from `es.json` that this component renders
- **images** — How images are resolved (if any)
- **example** — Actual content keys used in the current site

Key fallbacks (for FAQ, glossary, privacy): Components check multiple key names because
the content uses `q`/`a` format. See each entry for the fallback chain.

---

"""

for name, info in registry.items():
    section_ids = ", ".join(f"`{s}`" for s in info["section_ids"])
    md += f"## {name}\n\n"
    md += f"**Maps to section_ids:** {section_ids}  \n"
    md += f"**Content key pattern:** `{info.get('content_key', 'N/A')}`  \n"
    md += f"**Data access:** `{info['reads_from_pageContent']}`  \n"
    if info.get('data_shape'):
        md += f"**Data shape:** `{info['data_shape']}`  \n"
    if info.get('key_fallbacks'):
        md += f"**Key fallbacks:** {info['key_fallbacks']}  \n"
    if info.get('variant'):
        md += f"**Variant:** {info['variant']}  \n"
    if info.get('status'):
        md += f"**Status:** {info['status']}  \n"
    md += f"\n**Expected JSON structure:**\n\n```json\n{json.dumps(info['expects'], indent=2, ensure_ascii=False)}\n```\n\n"
    if info.get('images'):
        md += f"**Image resolution:**\n\n| Field | Use |\n|-------|-----|\n"
        for k, v in info['images'].items():
            md += f"| `{k}` | {v} |\n"
        md += "\n"
    if info.get('example'):
        md += f"**Current usage:** `{info['example']}`\n\n"
    md += "---\n\n"

write_file("/root/nexa-paraguay/docs/02-site/COMPONENT_REGISTRY.md", md)
print(f"Wrote {len(md)} chars")
"}

