                other = locales[loc]
                parts = path.split('.')
                found = True
                for p in parts:
                    if isinstance(other, dict) and p in other:
                        other = other[p]
                    else:
                        found = False
                        break
                if not found:
                    missing_by_locale[loc].append(path)
            walk_keys(v, path, missing_by_locale)
    elif isinstance(obj, list) and prefix:
        # Check if the array exists in other locales at same path
        for loc in ['en', 'nl', 'de']:
            other = locales[loc]
            parts = prefix.split('.')
            for p in parts:
                if isinstance(other, dict) and p in other:
                    other = other[p]
